    aggregation_funcs: Optional[Dict[str, Callable]] = None
) -> Dict[str, Dict[str, Any]]:
    """Aggregate search results by a metadata field with optional statistics.

    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping field_name to aggregation function.
            Example: {"score": max, "count": len}
            If None, defaults to count and average score per group

    Returns:
        Dictionary mapping group_value to aggregated statistics
        Example: {"tech": {"count": 5, "avg_score": 0.85, "max_score": 0.95}}
    """
    aggregated_data = defaultdict(lambda: {'count': 0, 'sum_score': 0.0, 'max_score': float('-inf'), 'min_score': float('inf')})

    # First pass: collect raw data for each group
    for result in search_results:
        group_key = result.metadata.get(group_by_field)
        if group_key is None:
            group_key = 'unknown'

        group_stats = aggregated_data[group_key]
        group_stats['count'] += 1
        group_stats['sum_score'] += result.score
        if result.score > group_stats['max_score']:
            group_stats['max_score'] = result.score
        if result.score < group_stats['min_score']:
            group_stats['min_score'] = result.score

    # Second pass: compute final statistics and apply custom aggregations
    final_aggregated = {}
    for group_key, stats in aggregated_data.items():
        group_dict = {}
        if stats['count'] > 0:
            group_dict['count'] = stats['count']
            group_dict['avg_score'] = stats['sum_score'] / stats['count']
            group_dict['max_score'] = stats['max_score']
            group_dict['min_score'] = stats['min_score']

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            for field_name, func in aggregation_funcs.items():
                # Extract field values from original results for this group
                field_values = []
                for result in search_results:
                    group_val = result.metadata.get(group_by_field)
                    if group_val is None:
                        group_val = 'unknown'
                    if group_val == group_key:
                        # Get field value (check both top-level and metadata)
                        if field_name == 'score':
                            field_values.append(result.score)
                        else:
                            field_values.append(result.metadata.get(field_name))

                # Filter out None values
                field_values = [v for v in field_values if v is not None]
                if field_values:
                    try:
                        group_dict[field_name] = func(field_values)
                    except Exception as e:
                        group_dict[field_name] = f"Error: {str(e)}"

        final_aggregated[group_key] = group_dict

    return final_aggregated
